// hooks/useSecureStorage.js
import { useState, useCallback, useEffect } from 'react';
import secureStorage from '../utils/secureStorage';

export function useSecureStorage(key, initialValue = null) {
  const [data, setData] = useState(initialValue);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const load = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const value = await secureStorage.secureGet(key);
      setData(value !== null ? value : initialValue);
    } catch (err) {
      setError(err.message);
      setData(initialValue);
    } finally {
      setLoading(false);
    }
  }, [key, initialValue]);

  const save = useCallback(
    async (value) => {
      try {
        setLoading(true);
        setError(null);
        await secureStorage.secureSet(key, value);
        setData(value);
        return true;
      } catch (err) {
        setError(err.message);
        return false;
      } finally {
        setLoading(false);
      }
    },
    [key]
  );

  const remove = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      await secureStorage.secureRemove(key);
      setData(initialValue);
      return true;
    } catch (err) {
      setError(err.message);
      return false;
    } finally {
      setLoading(false);
    }
  }, [key, initialValue]);

  useEffect(() => {
    load();
  }, [load]);

  return { data, loading, error, save, load, remove };
}

export function useUserProfile() {
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const loadProfile = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const data = await secureStorage.getUserProfile();
      setProfile(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  const saveProfile = useCallback(async (profileData) => {
    try {
      setLoading(true);
      setError(null);
      await secureStorage.saveUserProfile(profileData);
      setProfile(profileData);
      return true;
    } catch (err) {
      setError(err.message);
      return false;
    } finally {
      setLoading(false);
    }
  }, []);

  const updateProfile = useCallback(async (updates) => {
    try {
      setLoading(true);
      setError(null);
      await secureStorage.updateUserProfile(updates);
      const updated = await secureStorage.getUserProfile();
      setProfile(updated);
      return true;
    } catch (err) {
      setError(err.message);
      return false;
    } finally {
      setLoading(false);
    }
  }, []);

  const clearProfile = useCallback(async () => {
    try {
      setLoading(true);
      await secureStorage.removeUserProfile();
      setProfile(null);
      return true;
    } catch (err) {
      setError(err.message);
      return false;
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadProfile();
  }, [loadProfile]);

  return { profile, loading, error, saveProfile, updateProfile, clearProfile, loadProfile };
}

export function useAuthTokens() {
  const [tokens, setTokens] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  const loadTokens = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const data = await secureStorage.getAuthTokens();
      setTokens(data);
      setIsAuthenticated(!!data && !data.isExpired);
    } catch (err) {
      setError(err.message);
      setIsAuthenticated(false);
    } finally {
      setLoading(false);
    }
  }, []);

  const saveTokens = useCallback(async (tokenData) => {
    try {
      setLoading(true);
      setError(null);
      await secureStorage.saveAuthTokens(tokenData);
      setTokens(tokenData);
      setIsAuthenticated(true);
      return true;
    } catch (err) {
      setError(err.message);
      return false;
    } finally {
      setLoading(false);
    }
  }, []);

  const refreshAccessToken = useCallback(async (newToken, expiresAt) => {
    try {
      setError(null);
      await secureStorage.updateAccessToken(newToken, expiresAt);
      const updated = await secureStorage.getAuthTokens();
      setTokens(updated);
      setIsAuthenticated(true);
      return true;
    } catch (err) {
      setError(err.message);
      return false;
    }
  }, []);

  const logout = useCallback(async () => {
    try {
      setLoading(true);
      await secureStorage.clearUserData();
      setTokens(null);
      setIsAuthenticated(false);
      return true;
    } catch (err) {
      setError(err.message);
      return false;
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadTokens();
  }, [loadTokens]);

  return {
    tokens,
    loading,
    error,
    isAuthenticated,
    saveTokens,
    refreshAccessToken,
    logout,
    loadTokens
  };
}

